local baseLoadstring = loadstring
local loadstring = function(...)
	local res, err = baseLoadstring(...)
	if err and vape then
		vape:CreateNotification('Voidware', 'Failed to load : '..err, 30, 'alert')
	end
	return res
end
local isfile = isfile or function(file)
	local suc, res = pcall(function()
		return readfile(file)
	end)
	return suc and res ~= nil and res ~= ''
end
local function downloadFile(path, func)
	if not isfile(path) then
		local suc, res = pcall(function()
			return game:HttpGet('https://raw.githubusercontent.com/VapeVoidware/VoidwareBakup/main/'..select(1, path:gsub('vape/', '')), true)
		end)
		if not suc or res == '404: Not Found' then
			error(res)
		end
		if path:find('.lua') then
			res = '--This watermark is used to delete the file if its cached, remove it to make the file persist after vape updates.\n'..res
		end
		writefile(path, res)
	end
	return (func or readfile)(path)
end
local queue_on_teleport = queue_on_teleport or function() end
local cloneref = cloneref or function(obj)
	return obj
end

local function run(func)
	task.spawn(function()
		local suc, err = pcall(function()
			return func()
		end)
		if (not suc) then errorNotification("bedwars-main.lua error", debug.traceback(tostring(err)), 10) end
	end)
end

