        if type(remoteName) == "table" then
            remoteName = remoteName.instance.Name
        end
       	if remoteName == 'StepOnSnapTrap' and TrapDisabler.Enabled then
            return { SendToServer = function() end }
		elseif type(res) == "table" and res._custom then
