						if (not store.matchState == 2) then return end
					end))
				end)
			else
				pcall(function() playertween:Cancel() end)
				pcall(function() bedtween:Cancel() end)
			end
		end,
		Tooltip = "best paid autowin 2023!1!!! rel11!11!1"
	})
end)
